const express = require('express');
const app = express();

// ---------------------------------------------------------------------------
// 1. Security headers — remove X-Powered-By and add protective headers
// ---------------------------------------------------------------------------
app.disable('x-powered-by');
// In production, use helmet: const helmet = require('helmet'); app.use(helmet());

// ---------------------------------------------------------------------------
// 2. Body parsing with size limits to prevent large-payload DoS
// ---------------------------------------------------------------------------
app.use(express.json({ limit: '100kb' }));
app.use(express.urlencoded({ extended: false, limit: '100kb' }));

// ---------------------------------------------------------------------------
// 3. Request timeout to prevent slow-loris style attacks
// ---------------------------------------------------------------------------
app.use((req, res, next) => {
  req.setTimeout(10_000); // 10 seconds
  next();
});

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const allowedQueryKeys = ['name', 'id'];
  const unknownKeys = Object.keys(req.query).filter(
    (k) => !allowedQueryKeys.includes(k),
  );
  if (unknownKeys.length > 0) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Unknown query parameter(s): ${unknownKeys.join(', ')}`,
    });
  }

  // Sanitize / validate individual params when present
  if (req.query.id !== undefined && !/^\d+$/.test(req.query.id)) {
    return res.status(400).json({
      error: 'Bad Request',
      message: 'Parameter "id" must be a positive integer',
    });
  }

  if (
    req.query.name !== undefined &&
    (typeof req.query.name !== 'string' || req.query.name.length > 100)
  ) {
    return res.status(400).json({
      error: 'Bad Request',
      message: 'Parameter "name" must be a string of at most 100 characters',
    });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  let results = users;
  if (req.query.id) {
    results = results.filter((u) => u.id === Number(req.query.id));
  }
  if (req.query.name) {
    const needle = req.query.name.toLowerCase();
    results = results.filter((u) => u.name.toLowerCase().includes(needle));
  }

  res.json(results);
});

// ---------------------------------------------------------------------------
// 4. 404 handler — catch unmatched routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// ---------------------------------------------------------------------------
// 5. Global error handler — never leak stack traces to clients
// ---------------------------------------------------------------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err);
  res.status(err.status || 500).json({
    error: 'Internal Server Error',
    // Only expose message in development; hide in production
    ...(process.env.NODE_ENV !== 'production' && { message: err.message }),
  });
});

// ---------------------------------------------------------------------------
// 6. Start server — use PORT env var with fallback
// ---------------------------------------------------------------------------
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

